"""
title: Calculator Tool - Advanced Mathematical Operations
author: Torsten Feustel
version: 0.3.0
"""

import math
import cmath
import ast
import operator
from typing import Union, List, Dict, Any


class MathEngine:
    """Kern-Mathematik-Engine mit erweiterten Funktionen"""

    def __init__(self):
        self.functions = {
            # Basis-Mathematik
            "sin": math.sin,
            "cos": math.cos,
            "tan": math.tan,
            "asin": math.asin,
            "acos": math.acos,
            "atan": math.atan,
            "sinh": math.sinh,
            "cosh": math.cosh,
            "tanh": math.tanh,
            "asinh": math.asinh,
            "acosh": math.acosh,
            "atanh": math.atanh,
            "log": math.log,
            "ln": math.log,
            "log10": math.log10,
            "log2": math.log2,
            "exp": math.exp,
            "sqrt": math.sqrt,
            "abs": abs,
            "pow": pow,
            "factorial": math.factorial,
            "gamma": math.gamma,
            "floor": math.floor,
            "ceil": math.ceil,
            "round": round,
            "degrees": math.degrees,
            "radians": math.radians,
            # Kombinatorik
            "perm": lambda n, k: (
                math.factorial(n) // math.factorial(n - k) if n >= k >= 0 else 0
            ),
            "comb": lambda n, k: (
                math.factorial(n) // (math.factorial(k) * math.factorial(n - k))
                if n >= k >= 0
                else 0
            ),
            # Konstanten
            "pi": math.pi,
            "e": math.e,
            "tau": math.tau,
            # Hilfsfunktionen
            "min": min,
            "max": max,
            "sum": sum,
        }

        self.operators = {
            ast.Add: operator.add,
            ast.Sub: operator.sub,
            ast.Mult: operator.mul,
            ast.Div: operator.truediv,
            ast.Pow: operator.pow,
            ast.USub: operator.neg,
            ast.UAdd: operator.pos,
        }

    def evaluate(self, expression: str) -> Union[float, int, complex, str]:
        """Sichere Auswertung mathematischer Ausdrücke"""
        try:
            # Preprocessing
            expr = expression.replace("^", "**").replace("π", "pi")
            node = ast.parse(expr, mode="eval")
            return self._eval_node(node.body)
        except Exception as e:
            return f"Fehler: {str(e)}"

    def _eval_node(self, node):
        """Rekursive AST-Auswertung"""
        if isinstance(node, ast.Constant):
            return node.value
        elif isinstance(node, ast.Num):
            return node.n
        elif isinstance(node, ast.BinOp):
            left, right = self._eval_node(node.left), self._eval_node(node.right)
            return self.operators[type(node.op)](left, right)
        elif isinstance(node, ast.UnaryOp):
            operand = self._eval_node(node.operand)
            return self.operators[type(node.op)](operand)
        elif isinstance(node, ast.Call):
            func_name = node.func.id
            if func_name in self.functions:
                args = [self._eval_node(arg) for arg in node.args]
                return self.functions[func_name](*args)
            raise ValueError(f"Unbekannte Funktion: {func_name}")
        elif isinstance(node, ast.Name):
            if node.id in self.functions:
                return self.functions[node.id]
            raise ValueError(f"Unbekannte Variable: {node.id}")
        else:
            raise ValueError(f"Nicht unterstützt: {type(node)}")


class EquationSolver:
    """Numerischer Gleichungslöser"""

    @staticmethod
    def solve_for_zero(
        func_str: str,
        var: str,
        start: float = 0,
        end: float = 100,
        precision: float = 1e-6,
    ) -> float:
        """Löst f(x) = 0 numerisch mit Bisection-Verfahren"""
        engine = MathEngine()

        def f(x):
            expr = func_str.replace(var, str(x))
            result = engine.evaluate(expr)
            return result if isinstance(result, (int, float)) else float("nan")

        # Bisection-Verfahren
        a, b = start, end
        if f(a) * f(b) > 0:
            raise ValueError("Keine Nullstelle im Intervall gefunden")

        for _ in range(100):  # Max 100 Iterationen
            c = (a + b) / 2
            if abs(f(c)) < precision:
                return c
            if f(a) * f(c) < 0:
                b = c
            else:
                a = c
        return (a + b) / 2

    @staticmethod
    def solve_quadratic(a: float, b: float, c: float) -> Dict[str, Any]:
        """Löst quadratische Gleichung ax² + bx + c = 0"""
        discriminant = b**2 - 4 * a * c

        if discriminant > 0:
            sqrt_d = math.sqrt(discriminant)
            x1 = (-b + sqrt_d) / (2 * a)
            x2 = (-b - sqrt_d) / (2 * a)
            return {"x1": x1, "x2": x2, "type": "real"}
        elif discriminant == 0:
            x = -b / (2 * a)
            return {"x": x, "type": "double_root"}
        else:
            real = -b / (2 * a)
            imag = math.sqrt(-discriminant) / (2 * a)
            return {
                "x1": complex(real, imag),
                "x2": complex(real, -imag),
                "type": "complex",
            }


class StatEngine:
    """Statistik-Engine"""

    @staticmethod
    def analyze(numbers: List[float]) -> Dict[str, float]:
        """Vollständige statistische Analyse"""
        if not numbers:
            return {"error": "Keine Daten"}

        n = len(numbers)
        sorted_nums = sorted(numbers)
        mean = sum(numbers) / n

        # Median
        median = (
            (sorted_nums[n // 2 - 1] + sorted_nums[n // 2]) / 2
            if n % 2 == 0
            else sorted_nums[n // 2]
        )

        # Varianz und Standardabweichung
        variance = sum((x - mean) ** 2 for x in numbers) / n
        std_dev = math.sqrt(variance)

        return {
            "count": n,
            "sum": sum(numbers),
            "mean": mean,
            "median": median,
            "min": min(numbers),
            "max": max(numbers),
            "range": max(numbers) - min(numbers),
            "variance": variance,
            "std_dev": std_dev,
        }


class Tools:
    """Wissenschaftlicher Taschenrechner - Optimiert für KI-Nutzung"""

    def __init__(self):
        self.engine = MathEngine()
        self.solver = EquationSolver()
        self.stats = StatEngine()

    def calculate(self, expression: str) -> str:
        """Hauptrechenfunktion - berechnet mathematische Ausdrücke"""
        if not expression.strip():
            return "❌ Leerer Ausdruck"

        result = self.engine.evaluate(expression.strip())

        if isinstance(result, str):  # Fehler
            return result

        # Formatierung
        if isinstance(result, complex):
            if result.imag == 0:
                result = result.real
            else:
                return f"{result.real:.10g} + {result.imag:.10g}i"

        if isinstance(result, float) and result.is_integer():
            result = int(result)

        return (
            f"🧮 {expression} = {result:.12g}"
            if isinstance(result, float)
            else f"🧮 {expression} = {result}"
        )

    def solve_equation(
        self,
        equation: str,
        variable: str = "x",
        range_start: float = -100,
        range_end: float = 100,
    ) -> str:
        """Löst Gleichungen numerisch"""
        try:
            # Konvertiere "f(x) = g(x)" zu "f(x) - g(x) = 0"
            if "=" in equation:
                left, right = equation.split("=", 1)
                func_str = f"({left.strip()}) - ({right.strip()})"
            else:
                func_str = equation.strip()

            solution = self.solver.solve_for_zero(
                func_str, variable, range_start, range_end
            )
            return f"📐 Lösung: {variable} = {solution:.10g}"

        except Exception as e:
            return f"❌ Gleichungslösung fehlgeschlagen: {str(e)}"

    def solve_quadratic_equation(self, a: float, b: float, c: float) -> str:
        """Löst quadratische Gleichungen ax² + bx + c = 0"""
        if a == 0:
            return "❌ a darf nicht 0 sein"

        try:
            solution = self.solver.solve_quadratic(a, b, c)
            equation_str = f"{a}x² + {b}x + {c} = 0"

            if solution["type"] == "real":
                return f"📐 {equation_str}\n✅ x₁ = {solution['x1']:.10g}, x₂ = {solution['x2']:.10g}"
            elif solution["type"] == "double_root":
                return (
                    f"📐 {equation_str}\n✅ x = {solution['x']:.10g} (doppelte Wurzel)"
                )
            else:
                x1, x2 = solution["x1"], solution["x2"]
                return f"📐 {equation_str}\n✅ x₁ = {x1.real:.6g}+{x1.imag:.6g}i, x₂ = {x2.real:.6g}{x2.imag:.6g}i"

        except Exception as e:
            return f"❌ Fehler: {str(e)}"

    def statistics(self, numbers_str: str) -> str:
        """Berechnet statistische Kennwerte"""
        try:
            numbers = [float(x) for x in numbers_str.replace(",", " ").split()]
            if not numbers:
                return "❌ Keine Zahlen gefunden"

            stats = self.stats.analyze(numbers)
            if "error" in stats:
                return f"❌ {stats['error']}"

            return f"""📊 Statistik ({stats['count']} Werte):
📈 Mittelwert: {stats['mean']:.6g} | Median: {stats['median']:.6g}
📉 Min: {stats['min']:.6g} | Max: {stats['max']:.6g} | Spannweite: {stats['range']:.6g}
🔢 Summe: {stats['sum']:.6g} | Standardabw.: {stats['std_dev']:.6g}"""

        except Exception as e:
            return f"❌ Statistik-Fehler: {str(e)}"

    def batch_calculate(
        self, expression: str, variable: str, values: List[float]
    ) -> str:
        """Berechnet einen Ausdruck für mehrere Werte"""
        try:
            results = []
            for val in values:
                expr = expression.replace(variable, str(val))
                result = self.engine.evaluate(expr)
                if isinstance(result, str):  # Fehler
                    results.append(f"{val}: Fehler")
                else:
                    results.append(f"{val}: {result:.6g}")

            return f"🧮 {expression} für {variable}:\n" + "\n".join(results)

        except Exception as e:
            return f"❌ Batch-Berechnung fehlgeschlagen: {str(e)}"

    def convert_base(self, number: int, from_base: int = 10, to_base: int = 2) -> str:
        """Konvertiert zwischen Zahlensystemen"""
        try:
            if from_base == 10:
                decimal = number
            elif from_base in [2, 8, 16]:
                decimal = int(str(number), from_base)
            else:
                return f"❌ Basis {from_base} nicht unterstützt"

            if to_base == 10:
                result = str(decimal)
            elif to_base == 2:
                result = bin(decimal)[2:]
            elif to_base == 8:
                result = oct(decimal)[2:]
            elif to_base == 16:
                result = hex(decimal)[2:].upper()
            else:
                return f"❌ Basis {to_base} nicht unterstützt"

            bases = {2: "binär", 8: "oktal", 10: "dezimal", 16: "hexadezimal"}
            return f"🔢 {number} ({bases[from_base]}) = {result} ({bases[to_base]})"

        except Exception as e:
            return f"❌ Konversion fehlgeschlagen: {str(e)}"

    def get_calculator_help(self) -> str:
        """Zeigt verfügbare Funktionen"""
        return """🧮 Wissenschaftlicher Taschenrechner v3.0

🔧 Hauptfunktionen:
• calculate(expression) - Berechnet mathematische Ausdrücke
• solve_equation(equation, variable) - Löst Gleichungen numerisch
• solve_quadratic_equation(a, b, c) - Quadratische Gleichungen
• statistics(numbers) - Statistische Analyse
• batch_calculate(expr, var, values) - Mehrere Werte berechnen
• convert_base(number, from, to) - Zahlensystem-Konversion

🔬 Unterstützte Funktionen:
Trigonometrie: sin, cos, tan, asin, acos, atan, sinh, cosh, tanh
Logarithmen: log, ln, log10, log2, exp, sqrt, abs, pow
Kombinatorik: factorial, perm, comb, gamma
Konstanten: pi, e, tau

📐 Beispiele:
• calculate("sin(pi/4) + log(e)")
• solve_equation("exp(x) - 5", "x")
• batch_calculate("x**2 + 1", "x", [1,2,3,4,5])
• statistics("1, 2, 3, 4, 5")"""


# =============================================================================
# VERWENDUNGSBEISPIELE
# =============================================================================

if __name__ == "__main__":
    calc = Tools()

    print("=== WISSENSCHAFTLICHER TASCHENRECHNER V3.0 ===\n")
    print(calc.calculate("sin(pi/4) + cos(pi/4)"))
    print(calc.solve_quadratic_equation(1, -5, 6))
    print(calc.batch_calculate("exp(-0.23*t)", "t", [1, 5, 10, 15, 20]))
    print(calc.statistics("628, 1557, 4706, 13088, 30036"))
